import{_ as a,o,c as i,ag as l}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Dotfiles के बारे में (HI)","titleTemplate":":title","description":"Chezmoi द्वारा प्रबंधित अगली पीढ़ी की शेल कॉन्फ़िगरेशन। उच्च प्रदर्शन, सुरक्षित, और AI-नेटिव। macOS, Linux और WSL पर Dotfiles के माध्यम से संगत।","frontmatter":{"title":"Dotfiles के बारे में","description":"Chezmoi द्वारा प्रबंधित अगली पीढ़ी की शेल कॉन्फ़िगरेशन। उच्च प्रदर्शन, सुरक्षित, और AI-नेटिव। macOS, Linux और WSL पर Dotfiles के माध्यम से संगत।","lang":"hi-IN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Dotfiles के बारे में preview","canonical":"/hi/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Dotfiles के बारे में","pageType":"docs","schemaType":"WebPage","metaTitle":"Dotfiles के बारे में - Dotfiles (HI)","permalink":"/hi/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, कॉन्फ़िगरेशन, ऑटोमेशन, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Chezmoi द्वारा प्रबंधित अगली पीढ़ी की शेल कॉन्फ़िगरेशन। उच्च प्रदर्शन, सुरक्षित, और AI-नेटिव।"},{"name":"twitter:title","content":"Dotfiles के बारे में"},{"name":"og:title","content":"Dotfiles के बारे में"},{"name":"og:description","content":"Chezmoi द्वारा प्रबंधित अगली पीढ़ी की शेल कॉन्फ़िगरेशन। उच्च प्रदर्शन, सुरक्षित, और AI-नेटिव।"},{"name":"og:image:alt","content":"Dotfiles - आपकी शेल लाइफ के लिए डिज़ाइन किया गया"},{"name":"og:locale","content":"hi_IN"}]},"headers":[],"relativePath":"hi/about/index.md","filePath":"hi/about/index.md","lastUpdated":1773010926000}'),t={name:"hi/about/index.md"};function s(d,e,n,c,r,h){return o(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="dotfiles-के-बारे-में" tabindex="-1">Dotfiles के बारे में <a class="header-anchor" href="#dotfiles-के-बारे-में" aria-label="Permalink to &quot;Dotfiles के बारे में&quot;">​</a></h1><p>शेल कॉन्फ़िगरेशन के लिए आधुनिक मानक। सुरक्षित, क्रॉस-प्लेटफ़ॉर्म एनवायरनमेंट मैनेजमेंट के लिए <strong>Chezmoi</strong> पर निर्मित।</p><h2 id="खोजें" tabindex="-1">खोजें <a class="header-anchor" href="#खोजें" aria-label="Permalink to &quot;खोजें&quot;">​</a></h2><p>Dotfiles v0.2.495 आपके टर्मिनल को एक शक्तिशाली, एकीकृत कार्यक्षेत्र में बदल देता है। जटिल Makefiles या symlink स्क्रिप्ट्स पर निर्भर पुरानी dotfiles के विपरीत, Dotfiles एक टेम्पलेट-आधारित दृष्टिकोण का उपयोग करता है जो एटॉमिक, तेज़, और पुनरुत्पादन योग्य है।</p><h3 id="नया-क्या-है" tabindex="-1">नया क्या है <a class="header-anchor" href="#नया-क्या-है" aria-label="Permalink to &quot;नया क्या है&quot;">​</a></h3><ul><li><strong>आधुनिक कोर</strong> — उच्च-प्रदर्शन Rust विकल्प पुराने Unix टूल्स को रिप्लेस करते हैं: <ul><li><strong>Atuin</strong> शेल इतिहास के लिए</li><li><strong>Yazi</strong> फाइल मैनेजमेंट के लिए</li><li><strong>Zellij</strong> टर्मिनल मल्टीप्लेक्सिंग के लिए</li><li><strong>Ghostty</strong> GPU-एक्सेलेरेटेड टर्मिनल के लिए</li><li><strong>NeoVim</strong> आधुनिक एडिटिंग के लिए</li></ul></li><li><strong>नेटिव सुरक्षा</strong> — थर्ड-पार्टी एजेंट्स के बिना पूर्ण नेटिव SSH साइनिंग</li><li><strong>इंटरैक्टिव मोड</strong> — नया <code>dot learn</code> कमांड आपको फीचर्स के माध्यम से गाइड करता है</li></ul><h2 id="शुरू-करें" tabindex="-1">शुरू करें <a class="header-anchor" href="#शुरू-करें" aria-label="Permalink to &quot;शुरू करें&quot;">​</a></h2><h3 id="आवश्यकताएं" tabindex="-1">आवश्यकताएं <a class="header-anchor" href="#आवश्यकताएं" aria-label="Permalink to &quot;आवश्यकताएं&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong>, या <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> और <strong>Git</strong></li><li><strong>Chezmoi</strong> (स्वचालित रूप से इंस्टॉल)</li><li><strong>Nerd Font</strong> (टर्मिनल आइकन के लिए)</li></ul><h3 id="इंस्टॉल-करें" tabindex="-1">इंस्टॉल करें <a class="header-anchor" href="#इंस्टॉल-करें" aria-label="Permalink to &quot;इंस्टॉल करें&quot;">​</a></h3><p>संपूर्ण सूट इंस्टॉल करने के लिए एक कमांड चलाएं:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>इंस्टॉलर:</p><ol><li><code>chezmoi</code> बाइनरी इंस्टॉल करेगा</li><li>रिपॉजिटरी क्लोन करेगा</li><li>Homebrew (macOS) या Apt (Linux) के माध्यम से आवश्यक पैकेज इंस्टॉल करेगा</li><li>आपकी कॉन्फ़िगरेशन लागू करेगा</li></ol><h3 id="एक्सप्लोर-करें" tabindex="-1">एक्सप्लोर करें <a class="header-anchor" href="#एक्सप्लोर-करें" aria-label="Permalink to &quot;एक्सप्लोर करें&quot;">​</a></h3><p>इंस्टॉलेशन के बाद, अपना टर्मिनल पुनः आरंभ करें और चलाएं:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>यह आपके नए एनवायरनमेंट का एक इंटरैक्टिव टूर शुरू करता है।</p><h2 id="अनुकूलित-करें" tabindex="-1">अनुकूलित करें <a class="header-anchor" href="#अनुकूलित-करें" aria-label="Permalink to &quot;अनुकूलित करें&quot;">​</a></h2><p>आपकी कॉन्फ़िगरेशन <code>~/.local/share/chezmoi</code> में है:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # शेल एंट्री पॉइंट</span></span>
<span class="line"><span>├── dot_config/             # XDG बेस कॉन्फिग (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # शेल इतिहास</span></span>
<span class="line"><span>│   ├── ghostty/            # टर्मिनल एमुलेटर</span></span>
<span class="line"><span>│   ├── git/                # Git कॉन्फ़िगरेशन</span></span>
<span class="line"><span>│   ├── yazi/               # फाइल मैनेजर</span></span>
<span class="line"><span>│   ├── zellij/             # टर्मिनल मल्टीप्लेक्सर</span></span>
<span class="line"><span>│   ├── zsh/                # Zsh कॉन्फ़िगरेशन</span></span>
<span class="line"><span>│   └── shell/              # साझा एलियास और पाथ</span></span>
<span class="line"><span>├── provision/              # लाइफसाइकिल स्क्रिप्ट्स</span></span>
<span class="line"><span>├── install.sh              # यूनिवर्सल इंस्टॉलर</span></span>
<span class="line"><span>└── docs/                   # डॉक्यूमेंटेशन</span></span></code></pre></div><h2 id="मुख्य-कमांड" tabindex="-1">मुख्य कमांड <a class="header-anchor" href="#मुख्य-कमांड" aria-label="Permalink to &quot;मुख्य कमांड&quot;">​</a></h2><p><code>dot</code> CLI 53 कमांड को श्रेणी के अनुसार प्रदान करता है।</p><h3 id="कोर" tabindex="-1">कोर <a class="header-anchor" href="#कोर" aria-label="Permalink to &quot;कोर&quot;">​</a></h3><ul><li><code>dot apply</code> — कॉन्फ़िगरेशन परिवर्तन लागू करता है.</li><li><code>dot sync</code> — नवीनतम रिपॉजिटरी स्थिति प्राप्त करता है और लागू करता है.</li><li><code>dot update</code> — रिपॉजिटरी अपडेट करता है और कैश को वार्म करता है.</li><li><code>dot add</code> — Chezmoi स्रोत में नई फ़ाइलें जोड़ता है.</li><li><code>dot diff</code> — लागू करने से पहले लंबित परिवर्तन दिखाता है.</li><li><code>dot status</code> — प्रबंधित फ़ाइलों की स्थिति दिखाता है.</li><li><code>dot remove</code> — फ़ाइल को प्रबंधन से हटाता है और स्रोत प्रविष्टि मिटाता है.</li><li><code>dot cd</code> — Chezmoi स्रोत निर्देशिका में Shell खोलता है.</li><li><code>dot edit</code> — प्रबंधित फ़ाइल को आपके संपादक में खोलता है.</li><li><code>dot clean-cache</code> — अस्थायी कैश साफ़ करता है.</li><li><code>dot prewarm</code> — तेज़ Shell स्टार्टअप के लिए कैश पहले से भरता है.</li></ul><h3 id="निदान" tabindex="-1">निदान <a class="header-anchor" href="#निदान" aria-label="Permalink to &quot;निदान&quot;">​</a></h3><ul><li><code>dot doctor</code> — पथ, उपकरण और Shell स्थिति को सत्यापित करता है.</li><li><code>dot heal</code> — गुम या टूटी स्थिति को स्वचालित रूप से ठीक करता है.</li><li><code>dot health</code> — हल्का स्वास्थ्य जांच चलाता है.</li><li><code>dot verify</code> — स्रोत के विरुद्ध फ़ाइल अखंडता जांचता है.</li><li><code>dot scorecard</code> — कॉन्फ़िगरेशन गुणवत्ता स्कोर प्रिंट करता है.</li><li><code>dot snapshot</code> — बाद की तुलना के लिए वर्तमान स्थिति कैप्चर करता है.</li><li><code>dot smoke-test</code> — कोर टूलचेन को शुरू से अंत तक सत्यापित करता है.</li><li><code>dot chaos</code> — स्व-उपचार परीक्षण के लिए दोष इंजेक्ट करता है.</li><li><code>dot bundle</code> — पोर्टेबल कॉन्फ़िगरेशन बंडल निर्यात करता है.</li><li><code>dot rollback</code> — पिछले स्नैपशॉट पर वापस जाता है.</li><li><code>dot drift</code> — प्रबंधित फ़ाइलों में अप्रत्याशित परिवर्तन का पता लगाता है.</li><li><code>dot history</code> — apply/sync इतिहास लॉग दिखाता है.</li><li><code>dot benchmark</code> — Shell स्टार्टअप समय मापता है.</li><li><code>dot perf</code> — धीमी Shell आरंभीकरण को प्रोफ़ाइल करता है.</li></ul><h3 id="दिखावट" tabindex="-1">दिखावट <a class="header-anchor" href="#दिखावट" aria-label="Permalink to &quot;दिखावट&quot;">​</a></h3><ul><li><code>dot theme</code> — टर्मिनल रंग योजना बदलता है.</li><li><code>dot wallpaper</code> — डेस्कटॉप वॉलपेपर सेट करता है (macOS).</li><li><code>dot fonts</code> — Nerd Fonts इंस्टॉल या अपडेट करता है.</li><li><code>dot tune</code> — UI घनत्व और प्रॉम्प्ट शैली समायोजित करता है.</li></ul><h3 id="सुरक्षा" tabindex="-1">सुरक्षा <a class="header-anchor" href="#सुरक्षा" aria-label="Permalink to &quot;सुरक्षा&quot;">​</a></h3><ul><li><code>dot backup</code> — एन्क्रिप्टेड कॉन्फ़िगरेशन बैकअप बनाता है.</li><li><code>dot encrypt-check</code> — स्थिर अवस्था में गोपनीय एन्क्रिप्शन सत्यापित करता है.</li><li><code>dot firewall</code> — होस्ट फ़ायरवॉल नियम कॉन्फ़िगर करता है.</li><li><code>dot telemetry</code> — अनाम उपयोग टेलीमेट्री नियंत्रित करता है.</li><li><code>dot dns-doh</code> — DNS-over-HTTPS सक्षम करता है.</li><li><code>dot lock-screen</code> — स्क्रीन तुरंत लॉक करता है.</li><li><code>dot usb-safety</code> — USB मास-स्टोरेज ऑटो-माउंट प्रतिबंधित करता है.</li></ul><h3 id="गोपनीय" tabindex="-1">गोपनीय <a class="header-anchor" href="#गोपनीय" aria-label="Permalink to &quot;गोपनीय&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — गोपनीय बैकएंड आरंभ करता है (age / GPG).</li><li><code>dot secrets</code> — एन्क्रिप्टेड गोपनीय प्रविष्टियाँ सूचीबद्ध करता है.</li><li><code>dot secrets-create</code> — नया एन्क्रिप्टेड गोपनीय बनाता है.</li><li><code>dot ssh-key</code> — SSH कुंजी जोड़े उत्पन्न या रोटेट करता है.</li><li><code>dot ssh-cert</code> — CA से SSH प्रमाणपत्र का अनुरोध करता है.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — इंटरैक्टिव AI सहायक सत्र खोलता है.</li><li><code>dot ai-setup</code> — AI प्रदाताओं के लिए API कुंजियाँ कॉन्फ़िगर करता है.</li><li><code>dot ai-query</code> — AI मॉडल को एक-शॉट प्रॉम्प्ट भेजता है.</li><li>AI उपकरण रैपर: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="उपकरण" tabindex="-1">उपकरण <a class="header-anchor" href="#उपकरण" aria-label="Permalink to &quot;उपकरण&quot;">​</a></h3><ul><li><code>dot tools</code> — बंडल किए गए CLI प्रतिस्थापन और उनकी स्थिति सूचीबद्ध करता है.</li><li><code>dot new</code> — नई एलियास या फ़ंक्शन फ़ाइल बनाता है.</li><li><code>dot sandbox</code> — डिस्पोज़ेबल सैंडबॉक्स Shell खोलता है.</li><li><code>dot keys</code> — वर्तमान की बाइंडिंग दिखाता है.</li><li><code>dot learn</code> — इंटरैक्टिव ट्यूटोरियल शुरू करता है.</li></ul><h3 id="मेटा" tabindex="-1">मेटा <a class="header-anchor" href="#मेटा" aria-label="Permalink to &quot;मेटा&quot;">​</a></h3><ul><li><code>dot upgrade</code> — Dotfiles को नवीनतम रिलीज़ में अपग्रेड करता है.</li><li><code>dot packages</code> — Dotfiles द्वारा प्रबंधित इंस्टॉल किए गए पैकेज सूचीबद्ध करता है.</li><li><code>dot version</code> / <code>dot help</code> — संस्करण या उपयोग जानकारी प्रिंट करता है</li></ul><h2 id="योगदान-करें" tabindex="-1">योगदान करें <a class="header-anchor" href="#योगदान-करें" aria-label="Permalink to &quot;योगदान करें&quot;">​</a></h2><p>समुदाय में शामिल हों। हमारी <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">आचार संहिता</a> और <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">योगदान दिशानिर्देश</a> देखें।</p>`,41)])])}const m=a(t,[["render",s]]);export{u as __pageData,m as default};
